import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

function LandingPage() {
  const navigate = useNavigate();
  const [isLogin, setIsLogin] = useState(true);

  return (
    <div style={styles.container}>

      {/* LEFT SIDE */}
      <div style={styles.left}>
        <h1 style={styles.logo}>DocBook</h1>

        <h2 style={styles.heading}>
          Your Health, <br /> Simplified
        </h2>

        <p style={styles.text}>
          Book appointments with top doctors, manage your health records,
          and get the care you deserve — all in one place.
        </p>
      </div>

     {/* RIGHT SIDE */}
<div style={styles.right}>
  <div style={styles.card}>

    <h2 style={styles.cardTitle}>Welcome</h2>

    <p style={styles.subtitle}>
      Book appointments with trusted doctors easily
    </p>

    {/* Login Button */}
    <button
      style={styles.loginBtn}
      onClick={() => navigate("/login")}
    >
      Login
    </button>

    {/* Register Button */}
    <button
      style={styles.registerBtn}
      onClick={() => navigate("/register")}
    >
      Sign Up
    </button>

  </div>
</div>
    </div>
  );
}

export default LandingPage;

const styles = {
  container: {
    display: "flex",
    height: "100vh",
    fontFamily: "Segoe UI, sans-serif",
  },

  // LEFT SIDE
  left: {
    flex: 1,
    backgroundColor: "#2563EB", // ✅ MATCH NAVBAR
    color: "white",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    padding: "60px",
  },

  logo: {
    fontSize: "28px",
    marginBottom: "20px",
  },

  heading: {
    fontSize: "40px",
    marginBottom: "20px",
    lineHeight: "1.2",
  },

  text: {
    fontSize: "16px",
    maxWidth: "400px",
    opacity: 0.9,
  },

  // RIGHT SIDE
  right: {
    flex: 1,
    backgroundColor: "#f9fafb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  // CARD
  card: {
    backgroundColor: "white",
    padding: "40px",
    borderRadius: "12px",
    width: "320px",
    boxShadow: "0 8px 25px rgba(0,0,0,0.1)",
  },

  cardTitle: {
    marginBottom: "20px",
    textAlign: "center",
  },

  input: {
    width: "100%",
    padding: "10px",
    marginBottom: "15px",
    borderRadius: "6px",
    border: "1px solid #ddd",
  },

  mainBtn: {
    width: "100%",
    padding: "12px",
    backgroundColor: "#2563EB",
    color: "white",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
    fontWeight: "600",
  },

  switchText: {
    marginTop: "15px",
    fontSize: "14px",
    textAlign: "center",
  },

  link: {
    color: "#2563EB",
    cursor: "pointer",
    fontWeight: "600",
  },

  skip: {
    marginTop: "10px",
    textAlign: "center",
    fontSize: "13px",
    color: "#777",
    cursor: "pointer",
  },
};
